    title, poster, description, director, release_year, runtime,
    rating, view_count, video_url, is_free, status
) VALUES (
    #{title}, #{poster}, #{description}, #{director}, #{releaseYear},
    #{runtime}, #{rating}, #{viewCount}, #{videoUrl}, #{isFree}, #{status}
)

mapper.update:
UPDATE movie
title = #{title}, poster = #{poster}, description = #{description}, director = #{director}, release_year = #{releaseYear}, runtime = #{runtime}, rating = #{rating}, view_count = #{viewCount}, video_url = #{videoUrl}, is_free = #{isFree}, status = #{status},
WHERE id = #{id}
